@page "/"
@attribute [Authorize]

<PageTitle>VetClinic Dashboard</PageTitle>

<h1>🐾 Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4 mb-3">
        <div class="card text-center">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-4">@petCount</p>
                <a href="patients" class="btn btn-primary">Manage Patients</a>
            </div>
        </div>
    </div>
    <div class="col-md-4 mb-3">
        <div class="card text-center">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-4">@todayAppointments</p>
                <a href="appointments" class="btn btn-primary">View Schedule</a>
            </div>
        </div>
    </div>
    <div class="col-md-4 mb-3">
        <div class="card text-center">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-4">@pendingInvoices</p>
                <a href="billing" class="btn btn-primary">View Billing</a>
            </div>
        </div>
    </div>
</div>

@code {
    [Inject] private ApplicationDbContext Db { get; set; } = default!;

    private int petCount;
    private int todayAppointments;
    private int pendingInvoices;

    protected override void OnInitialized()
    {
        petCount = Db.Pets.Count();
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        todayAppointments = Db.Appointments.Count(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = Db.Invoices.Count(i => i.Status == InvoiceStatus.Pending);
    }
}

arguments.file_text:
@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer

@using Microsoft.EntityFrameworkCore

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col">
        <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-auto">
        <button class="btn btn-success" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-primary" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner?.Id > 0 ? "Edit" : "New") Owner</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label>First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.FirstName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.LastName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.Phone" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="CancelOwner">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet?.Id > 0 ? "Edit" : "New") Pet</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-2 mb-2">
                        <label>Name</label>
                        <InputText class="form-control" @bind-Value="editingPet!.Name" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Species</label>
                        <InputText class="form-control" @bind-Value="editingPet!.Species" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet!.Breed" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet!.DateOfBirth" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet!.WeightKg" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Owner</label>
                        <InputSelect class="form-control" @bind-Value="editingPet!.OwnerId">
                            <option value="0">-- Select --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="CancelPet">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>Pet</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var pet in FilteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ViewHistory(pet)">History</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (selectedPet != null)
{
    <div class="card mt-3">
        <div class="card-header d-flex justify-content-between">
            <span>Medical History — @selectedPet.Name</span>
            <button class="btn btn-sm btn-success" @onclick="ShowAddTreatment">+ Add Treatment</button>
        </div>
        <div class="card-body">
            @if (showTreatmentForm)
            {
                <EditForm Model="editingTreatment" OnValidSubmit="SaveTreatment" FormName="treatmentForm">
                    <DataAnnotationsValidator />
                    <div class="row mb-2">
                        <div class="col-md-3">
                            <label>Date</label>
                            <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingTreatment!.Date" />
                        </div>
                        <div class="col-md-3">
                            <label>Description</label>
                            <InputText class="form-control" @bind-Value="editingTreatment!.Description" />
                        </div>
                        <div class="col-md-2">
                            <label>Veterinarian</label>
                            <InputText class="form-control" @bind-Value="editingTreatment!.Veterinarian" />
                        </div>
                        <div class="col-md-2">
                            <label>Cost</label>
                            <InputNumber class="form-control" @bind-Value="editingTreatment!.Cost" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label>Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editingTreatment!.Notes" />
                    </div>
                    <button type="submit" class="btn btn-primary btn-sm">Save</button>
                    <button type="button" class="btn btn-secondary btn-sm" @onclick="() => showTreatmentForm = false">Cancel</button>
                </EditForm>
                <hr />
            }

            @if (!treatments.Any())
            {
                <p class="text-muted">No treatments recorded yet.</p>
            }
            else
            {
