@code {
    [Inject] private ApplicationDbContext Db { get; set; } = default!;

    private List<Invoice> invoices = [];
    private List<Owner> owners = [];
    private string statusFilter = "";
    private bool showInvoiceForm, showPaymentForm;
    private Invoice? selectedInvoice;
    private Invoice? paymentInvoice;

    // New invoice fields
    private int newInvoiceOwnerId;
    private string newInvoiceDescription = "";
    private DateTime? newInvoiceDueDate;
    private List<InvoiceItem> newInvoiceItems = [new()];

    // Payment fields
    private decimal paymentAmount;
    private PaymentMethod paymentMethod = PaymentMethod.Cash;
    private string paymentReference = "";

    protected override void OnInitialized()
    {
        owners = Db.Owners.OrderBy(o => o.LastName).ToList();
        LoadInvoices();
    }

    private void LoadInvoices()
    {
        var query = Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<InvoiceStatus>(statusFilter, out var status))
            query = query.Where(i => i.Status == status);

        invoices = query.ToList();
    }

    private void ShowNewInvoice()
    {
        newInvoiceOwnerId = 0;
        newInvoiceDescription = "";
        newInvoiceDueDate = DateTime.Today.AddDays(30);
        newInvoiceItems = [new()];
        showInvoiceForm = true;
    }

    private void SaveInvoice()
    {
        if (newInvoiceOwnerId == 0) return;
        var invoice = new Invoice
        {
            OwnerId = newInvoiceOwnerId,
            Description = newInvoiceDescription,
            DueDate = newInvoiceDueDate,
            Items = newInvoiceItems.Where(i => !string.IsNullOrWhiteSpace(i.Description)).ToList()
        };
        Db.Invoices.Add(invoice);
        Db.SaveChanges();
        showInvoiceForm = false;
        LoadInvoices();
    }

    private void ViewInvoice(Invoice inv)
    {
        selectedInvoice = inv;
    }

    private void ShowPayment(Invoice inv)
    {
        paymentInvoice = inv;
        paymentAmount = inv.Balance;
        paymentMethod = PaymentMethod.Cash;
        paymentReference = "";
        showPaymentForm = true;
    }

    private void ProcessPayment()
    {
        if (paymentAmount <= 0 || paymentInvoice == null) return;

        var payment = new Payment
        {
            InvoiceId = paymentInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Reference = paymentReference,
            Date = DateTime.Now
        };
        Db.Payments.Add(payment);

        // Update invoice status
        var totalPaid = paymentInvoice.AmountPaid + paymentAmount;
        if (totalPaid >= paymentInvoice.Total)
            paymentInvoice.Status = InvoiceStatus.Paid;
        else
            paymentInvoice.Status = InvoiceStatus.PartiallyPaid;

        Db.SaveChanges();
        showPaymentForm = false;
        LoadInvoices();
    }

    private void CancelInvoice(Invoice inv)
    {
        inv.Status = InvoiceStatus.Cancelled;
        Db.SaveChanges();
        LoadInvoices();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };
}

