    private Pet? editingPet;
    private Pet? selectedPet;
    private Treatment? editingTreatment;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override void OnInitialized() => LoadData();

    private void LoadData()
    {
        pets = Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToList();
        owners = Db.Owners.OrderBy(o => o.LastName).ToList();
    }

    private void ShowAddOwner() { editingOwner = new Owner(); showOwnerForm = true; }
    private void CancelOwner() { showOwnerForm = false; }
    private void ShowAddPet() { editingPet = new Pet(); showPetForm = true; }
    private void CancelPet() { showPetForm = false; }

    private void SaveOwner()
    {
