        else Db.Owners.Update(editingOwner);
        Db.SaveChanges();
        showOwnerForm = false;
        LoadData();
    }

    private void EditPet(Pet pet) { editingPet = pet; showPetForm = true; }

    private void SavePet()
    {
        if (editingPet!.Id == 0) Db.Pets.Add(editingPet);
        else Db.Pets.Update(editingPet);
        Db.SaveChanges();
        showPetForm = false;
        LoadData();
    }

    private void ViewHistory(Pet pet)
    {
        selectedPet = pet;
        treatments = Db.Treatments.Where(t => t.PetId == pet.Id).OrderByDescending(t => t.Date).ToList();
    }

    private void ShowAddTreatment()
    {
        editingTreatment = new Treatment { PetId = selectedPet!.Id, Date = DateTime.Now };
        showTreatmentForm = true;
    }

    private void SaveTreatment()
    {
        Db.Treatments.Add(editingTreatment!);
        Db.SaveChanges();
        showTreatmentForm = false;
        ViewHistory(selectedPet!);
    }
}

