@using Microsoft.EntityFrameworkCore

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label>View Date</label>
        <input type="date" class="form-control" @bind="viewDate" @bind:event="onchange" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3">
        <label>Veterinarian</label>
        <select class="form-control" @bind="filterVet" @bind:after="LoadAppointments">
            <option value="">All</option>
            @foreach (var vet in veterinarians)
            {
                <option value="@vet">@vet</option>
            }
        </select>
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-success" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment?.Id > 0 ? "Edit" : "New") Appointment</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label>Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingAppointment!.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in allPets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Start</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment!.StartTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>End</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment!.EndTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment!.Veterinarian" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment!.Reason" />
                    </div>
                </div>
                <div class="mb-2">
                    <label>Notes</label>
                    <InputTextArea class="form-control" @bind-Value="editingAppointment!.Notes" />
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (!string.IsNullOrEmpty(conflictMessage))
{
    <div class="alert alert-warning">@conflictMessage</div>
}

<h4>Schedule for @viewDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead>
                <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Vet</th><th>Reason</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var apt in filteredAppointments)
                {
                    <tr class="@GetRowClass(apt)">
                        <td>@apt.StartTime.ToString("HH:mm") – @apt.EndTime.ToString("HH:mm")</td>
                        <td>@apt.Pet.Name</td>
                        <td>@apt.Pet.Owner.FullName</td>
                        <td>@apt.Veterinarian</td>
                        <td>@apt.Reason</td>
                        <td>@apt.Status</td>
                        <td>
                            @if (apt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                            }
                        </td>
                    </tr>
                }
                @if (!filteredAppointments.Any())
                {
                    <tr><td colspan="7" class="text-muted text-center">No appointments for this date.</td></tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Available Slots</div>
            <div class="card-body">
                @foreach (var slot in availableSlots)
                {
                    <span class="badge bg-success me-1 mb-1">@slot</span>
                }
                @if (!availableSlots.Any())
                {
                    <p class="text-muted">No available slots.</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Inject] private ApplicationDbContext Db { get; set; } = default!;

    private DateTime viewDate = DateTime.Today;
    private string filterVet = "";
    private bool showForm;
    private Appointment? editingAppointment;
    private List<Appointment> appointments = [];
    private List<Pet> allPets = [];
    private List<string> veterinarians = [];
    private List<string> availableSlots = [];
    private string? conflictMessage;

    private IEnumerable<Appointment> filteredAppointments => string.IsNullOrEmpty(filterVet)
        ? appointments
        : appointments.Where(a => a.Veterinarian == filterVet);

    protected override void OnInitialized()
    {
        allPets = Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToList();
        veterinarians = Db.Appointments.Where(a => a.Veterinarian != null).Select(a => a.Veterinarian!).Distinct().ToList();
        LoadAppointments();
    }

    private void LoadAppointments()
    {
        var dayStart = viewDate.Date;
        var dayEnd = dayStart.AddDays(1);
        appointments = Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
            .OrderBy(a => a.StartTime)
            .ToList();
        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots = [];
        var start = viewDate.Date.AddHours(8);
        var end = viewDate.Date.AddHours(18);
        var scheduled = appointments.Where(a => a.Status == AppointmentStatus.Scheduled).ToList();

        for (var time = start; time < end; time = time.AddMinutes(30))
        {
            var slotEnd = time.AddMinutes(30);
            bool isFree = !scheduled.Any(a => a.StartTime < slotEnd && a.EndTime > time);
            if (isFree)
                availableSlots.Add(time.ToString("HH:mm"));
        }
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment
        {
            StartTime = viewDate.Date.AddHours(9),
            EndTime = viewDate.Date.AddHours(9).AddMinutes(30)
        };
        showForm = true;
        conflictMessage = null;
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        showForm = true;
        conflictMessage = null;
    }

    private void SaveAppointment()
    {
        // Check for conflicts
        var conflicts = Db.Appointments.Any(a =>
            a.Id != editingAppointment!.Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.Veterinarian == editingAppointment.Veterinarian &&
            a.StartTime < editingAppointment.EndTime &&
            a.EndTime > editingAppointment.StartTime);

        if (conflicts)
        {
            conflictMessage = "Time conflict detected for this veterinarian. Please choose another slot.";
            return;
        }

        if (editingAppointment!.Id == 0)
            Db.Appointments.Add(editingAppointment);
        else
            Db.Appointments.Update(editingAppointment);

        Db.SaveChanges();
        showForm = false;
        conflictMessage = null;

        if (!veterinarians.Contains(editingAppointment.Veterinarian ?? ""))
            veterinarians = Db.Appointments.Where(a => a.Veterinarian != null).Select(a => a.Veterinarian!).Distinct().ToList();

        LoadAppointments();
    }

    private void Cancel(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        Db.SaveChanges();
        LoadAppointments();
    }

    private void Complete(Appointment apt)
    {
        apt.Status = AppointmentStatus.Completed;
        Db.SaveChanges();
        LoadAppointments();
    }

    private string GetRowClass(Appointment apt) => apt.Status switch
    {
        AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        AppointmentStatus.Completed => "table-success",
        _ => ""
    };
}
