                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                            }
                        </td>
                    </tr>
                }
                @if (!filteredAppointments.Any())
                {
                    <tr><td colspan="7" class="text-muted text-center">No appointments for this date.</td></tr>
                }
            </tbody>
        </table>
