                    <input type="text" class="form-control" @bind="newInvoiceDescription" />
                </div>
                <div class="col-md-4">
                    <label>Due Date</label>
                    <input type="date" class="form-control" @bind="newInvoiceDueDate" />
                </div>
            </div>

            <h6>Line Items</h6>
            @for (int i = 0; i < newInvoiceItems.Count; i++)
            {
                var idx = i;
                <div class="row mb-1">
                    <div class="col-md-6">
                        <input type="text" class="form-control form-control-sm" placeholder="Description"
                               @bind="newInvoiceItems[idx].Description" />
                    </div>
                    <div class="col-md-3">
                        <input type="number" class="form-control form-control-sm" placeholder="Amount" step="0.01"
                               @bind="newInvoiceItems[idx].Amount" />
                    </div>
                    <div class="col-md-3">
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => newInvoiceItems.RemoveAt(idx)">Remove</button>
                    </div>
                </div>
            }
            <button class="btn btn-sm btn-outline-secondary mb-2" @onclick='() => newInvoiceItems.Add(new InvoiceItem())'>+ Add Item</button>

            <div>
                <button class="btn btn-primary" @onclick="SaveInvoice">Create Invoice</button>
                <button class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
            </div>
        </div>
