<table class="table table-striped">
    <thead>
        <tr><th>#</th><th>Owner</th><th>Date</th><th>Description</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>@inv.Id</td>
                <td>@inv.Owner.FullName</td>
                <td>@inv.CreatedDate.ToString("d")</td>
                <td>@inv.Description</td>
                <td>@inv.Total.ToString("C")</td>
                <td>@inv.AmountPaid.ToString("C")</td>
                <td>@inv.Balance.ToString("C")</td>
                <td><span class="badge @GetStatusBadge(inv.Status)">@inv.Status</span></td>
                <td>
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ViewInvoice(inv)">View</button>
                    @if (inv.Status != InvoiceStatus.Paid && inv.Status != InvoiceStatus.Cancelled)
                    {
                        <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPayment(inv)">Pay</button>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelInvoice(inv)">Cancel</button>
                    }
                </td>
            </tr>
        }
    </tbody>
</table>

@if (selectedInvoice != null)
{
